The first verifiable production slice is a single-module boundary-and-calculation implementation: parse `unknown` once at the trust boundary, reject malformed fields with a field-specific `QuoteInputError`, then compute the quote with straight-line cent arithmetic.

```ts
export type QuoteRequest = {
  customerKind: "retail" | "trade";
  subtotalCents: number;
  destination: "domestic" | "international";
  expedited?: boolean;
};

export type Quote = {
  subtotalCents: number;
  discountCents: number;
  shippingCents: number;
  totalCents: number;
};

export class QuoteInputError extends Error {
  readonly field: string;

  constructor(field: string, message = `Invalid field: ${field}`) {
    super(message);
    this.name = "QuoteInputError";
    this.field = field;
  }
}

const CUSTOMER_KINDS = ["retail", "trade"] as const;
const DESTINATIONS = ["domestic", "international"] as const;
const DOMESTIC_SHIPPING_CENTS = 500;
const INTERNATIONAL_SHIPPING_CENTS = 1500;
const EXPEDITED_SURCHARGE_CENTS = 700;

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null;
}

function requireEnum<T extends string>(
  record: Record<string, unknown>,
  field: string,
  allowed: readonly T[],
): T {
  const value = record[field];
  if (typeof value !== "string" || !allowed.includes(value as T)) {
    throw new QuoteInputError(field);
  }
  return value as T;
}

function requireNonnegativeInteger(
  record: Record<string, unknown>,
  field: string,
): number {
  const value = record[field];
  if (typeof value !== "number" || !Number.isInteger(value) || value < 0) {
    throw new QuoteInputError(field);
  }
  return value;
}

function requireOptionalBoolean(
  record: Record<string, unknown>,
  field: string,
): boolean {
  const value = record[field];
  if (value === undefined) {
    return false;
  }
  if (typeof value !== "boolean") {
    throw new QuoteInputError(field);
  }
  return value;
}

function parseQuoteRequest(input: unknown): QuoteRequest {
  if (!isRecord(input)) {
    throw new QuoteInputError("input", "Input must be an object");
  }

  return {
    customerKind: requireEnum(input, "customerKind", CUSTOMER_KINDS),
    subtotalCents: requireNonnegativeInteger(input, "subtotalCents"),
    destination: requireEnum(input, "destination", DESTINATIONS),
    expedited: requireOptionalBoolean(input, "expedited"),
  };
}

export function quoteOrder(input: unknown): Quote {
  const request = parseQuoteRequest(input);

  const discountCents =
    request.customerKind === "trade"
      ? Math.floor(request.subtotalCents * 0.1)
      : 0;

  const baseShippingCents =
    request.destination === "domestic"
      ? DOMESTIC_SHIPPING_CENTS
      : INTERNATIONAL_SHIPPING_CENTS;

  const shippingCents =
    baseShippingCents + (request.expedited ? EXPEDITED_SURCHARGE_CENTS : 0);

  const totalCents =
    request.subtotalCents - discountCents + shippingCents;

  return {
    subtotalCents: request.subtotalCents,
    discountCents,
    shippingCents,
    totalCents,
  };
}
```

Tests for the smallest useful slice:

```ts
import { describe, expect, it } from "vitest";
import { QuoteInputError, quoteOrder } from "./quoteOrder";

describe("quoteOrder", () => {
  it("quotes a retail domestic order", () => {
    expect(
      quoteOrder({
        customerKind: "retail",
        subtotalCents: 2000,
        destination: "domestic",
      }),
    ).toEqual({
      subtotalCents: 2000,
      discountCents: 0,
      shippingCents: 500,
      totalCents: 2500,
    });
  });

  it("quotes a trade international expedited order with floor discount", () => {
    expect(
      quoteOrder({
        customerKind: "trade",
        subtotalCents: 1999,
        destination: "international",
        expedited: true,
      }),
    ).toEqual({
      subtotalCents: 1999,
      discountCents: 199,
      shippingCents: 2200,
      totalCents: 4000,
    });
  });

  it("defaults expedited to false", () => {
    expect(
      quoteOrder({
        customerKind: "trade",
        subtotalCents: 1000,
        destination: "domestic",
      }),
    ).toEqual({
      subtotalCents: 1000,
      discountCents: 100,
      shippingCents: 500,
      totalCents: 1400,
    });
  });

  it.each([
    [null, "input"],
    [{}, "customerKind"],
    [{ customerKind: "vip", subtotalCents: 100, destination: "domestic" }, "customerKind"],
    [{ customerKind: "retail", subtotalCents: -1, destination: "domestic" }, "subtotalCents"],
    [{ customerKind: "retail", subtotalCents: 12.5, destination: "domestic" }, "subtotalCents"],
    [{ customerKind: "retail", subtotalCents: 100, destination: "mars" }, "destination"],
    [{ customerKind: "retail", subtotalCents: 100, destination: "domestic", expedited: "yes" }, "expedited"],
  ])("rejects malformed input %#", (input, field) => {
    try {
      quoteOrder(input);
      throw new Error("expected QuoteInputError");
    } catch (error) {
      expect(error).toBeInstanceOf(QuoteInputError);
      expect((error as QuoteInputError).field).toBe(field);
    }
  });
});
```

Construction decisions:

- Input validation: treat the HTTP JSON body as hostile. Convert `unknown` to a trusted local shape once, up front. Do not smear validation across pricing logic.
- Data meaning: `subtotalCents` is not “any number”; it is a nonnegative integer count of cents. That invariant belongs in boundary validation.
- Arithmetic: keep all money values in integer cents. `Math.floor(subtotalCents * 0.1)` matches the required trade discount rule exactly.
- Control shape: one parse phase and one compute phase is the smallest readable shape. No table or extra abstraction is justified yet.
- Error semantics: use a dedicated `QuoteInputError` with a `field` property so the caller can map failures deterministically to a `400` and a field-specific response.
- Smallest verifiable increment: cover one retail case, one trade+expedited case, omitted `expedited`, and one invalid case per field. That exercises every required rule without dragging in HTTP adapters or persistence.

This is a read-only engineering analysis. I did not modify files or run repository tests.
